import React, { useState, useEffect } from 'react';
import { getUsers } from '../api/api';

function Login({ onLogin }) {
  const [isAdmin, setIsAdmin] = useState(false);
  const [users, setUsers] = useState([]);
  const [selectedUserId, setSelectedUserId] = useState('');
  const [adminUsername, setAdminUsername] = useState('');
  const [adminPassword, setAdminPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!isAdmin) {
      fetchUsers();
    }
  }, [isAdmin]);

  const fetchUsers = async () => {
    setLoading(true);
    try {
      const res = await getUsers();
      setUsers(res.data);
      if (res.data.length > 0) {
        setSelectedUserId(res.data[0].id.toString());
      }
    } catch (err) {
      console.error("Failed to load users:", err);
      setError("Could not load library users. Is the backend running?");
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setError('');

    if (isAdmin) {
      if (adminUsername === 'admin' && adminPassword === 'admin') {
        onLogin({ role: 'admin', id: 0, name: 'Administrator' });
      } else {
        setError('Invalid admin credentials. Use admin / admin');
      }
    } else {
      if (!selectedUserId) {
        setError('Please select or create a user first.');
        return;
      }
      const user = users.find(u => u.id.toString() === selectedUserId);
      if (user) {
        onLogin({ role: 'user', id: user.id, name: user.name });
      } else {
        setError('Selected user not found.');
      }
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <div className="login-header">
          <h2>Library Portal Access</h2>
          <p>Choose your login method below</p>
        </div>

        <div className="login-toggle">
          <button
            type="button"
            className={`toggle-btn ${!isAdmin ? 'active' : ''}`}
            onClick={() => { setIsAdmin(false); setError(''); }}
          >
            Library Member
          </button>
          <button
            type="button"
            className={`toggle-btn ${isAdmin ? 'active' : ''}`}
            onClick={() => { setIsAdmin(true); setError(''); }}
          >
            Administrator
          </button>
        </div>

        {error && <div className="login-error">{error}</div>}

        <form onSubmit={handleSubmit} className="login-form">
          {!isAdmin ? (
            <div className="form-group">
              <label htmlFor="userSelect">Select Member Profile</label>
              {loading ? (
                <p>Loading members...</p>
              ) : users.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '10px 0' }}>
                  <p style={{ color: '#7f8c8d', margin: '0 0 10px 0', fontSize: '14px' }}>No members registered yet.</p>
                  <p style={{ fontSize: '13px', margin: 0 }}>
                    Please ask an Admin to register you, or login as Admin (username: <code>admin</code>, password: <code>admin</code>) to create users.
                  </p>
                </div>
              ) : (
                <select
                  id="userSelect"
                  value={selectedUserId}
                  onChange={(e) => setSelectedUserId(e.target.value)}
                  required
                >
                  {users.map(u => (
                    <option key={u.id} value={u.id}>
                      {u.name} (ID: {u.id} - {u.email})
                    </option>
                  ))}
                </select>
              )}
            </div>
          ) : (
            <>
              <div className="form-group">
                <label htmlFor="adminUsername">Username</label>
                <input
                  type="text"
                  id="adminUsername"
                  placeholder="Enter admin username (admin)"
                  value={adminUsername}
                  onChange={(e) => setAdminUsername(e.target.value)}
                  required
                />
              </div>
              <div className="form-group">
                <label htmlFor="adminPassword">Password</label>
                <input
                  type="password"
                  id="adminPassword"
                  placeholder="Enter admin password (admin)"
                  value={adminPassword}
                  onChange={(e) => setAdminPassword(e.target.value)}
                  required
                />
              </div>
            </>
          )}

          <button
            type="submit"
            className="btn btn-primary btn-block"
            disabled={!isAdmin && users.length === 0}
            style={{ marginTop: '10px' }}
          >
            Login as {isAdmin ? 'Administrator' : 'Member'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default Login;
